patch:
diff --git a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
index da5be383df15..e1384784d5db 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1389,11 +1389,47 @@ static void generateReproducer(CmpInst *Cond, Module *M,
   assert(!verifyFunction(*F, &dbgs()));
 }

+static bool hasLargeConstantInExpr(Value *V) {
+  if (auto *CI = dyn_cast<ConstantInt>(V)) {
+    // Check if the absolute value is large enough to potentially cause
+    // coefficient overflow when used in arithmetic operations.
+    // Use a conservative threshold of 100000 to avoid overflow in
+    // intermediate calculations.
+    const int64_t Threshold = 100000;
+    if (CI->getValue().getBitWidth() <= 64) {
+      int64_t Val = CI->getSExtValue();
+      if (Val < -Threshold || Val > Threshold)
+        return true;
+    }
+    // For larger bit widths, be conservative
+    else {
+      return true;
+    }
+  }
+  
+  if (auto *BO = dyn_cast<BinaryOperator>(V)) {
+    for (unsigned i = 0; i < BO->getNumOperands(); ++i) {
+      if (hasLargeConstantInExpr(BO->getOperand(i)))
+        return true;
+    }
+  }
+  
+  return false;
+}
+
 static std::optional<bool> checkCondition(CmpInst::Predicate Pred, Value *A,
                                           Value *B, Instruction *CheckInst,
                                           ConstraintInfo &Info) {
   LLVM_DEBUG(dbgs() << "Checking " << *CheckInst << "\n");

+  // Be conservative with conditions involving large constants,
+  // as they can cause coefficient overflow during decomposition,
+  // leading to incorrect constraint solving.
+  if (hasLargeConstantInExpr(A) || hasLargeConstantInExpr(B)) {
+    LLVM_DEBUG(dbgs() << "   conservative: condition involves large constants\n");
+    return std::nullopt;
+  }
+
   auto R = Info.getConstraintForSolving(Pred, A, B);
   if (R.empty() || !R.isValid(Info)){
     LLVM_DEBUG(dbgs() << "   failed to decompose condition\n");

