index da5be383df15..d1190ceae2b6 100644
--- a/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
+++ b/llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@ -1389,11 +1389,33 @@ static void generateReproducer(CmpInst *Cond, Module *M,
   assert(!verifyFunction(*F, &dbgs()));
 }

+static unsigned getArithmeticDepth(Value *V) {
+  if (auto *BO = dyn_cast<BinaryOperator>(V)) {
+    if (BO->getOpcode() == Instruction::Add ||
+        BO->getOpcode() == Instruction::Sub ||
+        BO->getOpcode() == Instruction::Mul) {
+      return 1 + std::max(getArithmeticDepth(BO->getOperand(0)),
+                         getArithmeticDepth(BO->getOperand(1)));
+    }
+  }
+  return 0;
+}
+
 static std::optional<bool> checkCondition(CmpInst::Predicate Pred, Value *A,
                                           Value *B, Instruction *CheckInst,
                                           ConstraintInfo &Info) {
   LLVM_DEBUG(dbgs() << "Checking " << *CheckInst << "\n");

+  // Be conservative with conditions involving deep chains of arithmetic
+  // operations, as coefficient overflow during decomposition can lead
+  // to incorrect constraints.
+  const unsigned MaxArithmeticDepth = 2;
+  if (getArithmeticDepth(A) > MaxArithmeticDepth ||
+      getArithmeticDepth(B) > MaxArithmeticDepth) {
+    LLVM_DEBUG(dbgs() << "   conservative: arithmetic depth exceeds threshold\n");
+    return std::nullopt;
+  }
+
   auto R = Info.getConstraintForSolving(Pred, A, B);
   if (R.empty() || !R.isValid(Info)){
     LLVM_DEBUG(dbgs() << "   failed to decompose condition\n");
