   assert(!verifyFunction(*F, &dbgs()));
 }

+static bool hasNSWMultiplication(Value *V) {
+  if (auto *BO = dyn_cast<BinaryOperator>(V)) {
+    if (BO->getOpcode() == Instruction::Mul && BO->hasNoSignedWrap())
+      return true;
+    if (BO->getNumOperands() >= 2) {
+      for (unsigned i = 0; i < BO->getNumOperands(); ++i) {
+        if (hasNSWMultiplication(BO->getOperand(i)))
+          return true;
+      }
+    }
+  }
+  return false;
+}
+
 static std::optional<bool> checkCondition(CmpInst::Predicate Pred, Value *A,
                                           Value *B, Instruction *CheckInst,
                                           ConstraintInfo &Info) {
   LLVM_DEBUG(dbgs() << "Checking " << *CheckInst << "\n");

+  // Be conservative with conditions involving NSW multiplication,
+  // as the linear constraint system may not accurately represent
+  // the non-linear behavior and wrap semantics.
+  if (hasNSWMultiplication(A) || hasNSWMultiplication(B)) {
+    LLVM_DEBUG(dbgs() << "   conservative: condition involves NSW multiplication\n");
+    return std::nullopt;
+  }
+
   auto R = Info.getConstraintForSolving(Pred, A, B);
   if (R.empty() || !R.isValid(Info)){
     LLVM_DEBUG(dbgs() << "   failed to decompose condition\n");
